import React, { useState, useEffect } from 'react';
import axios from 'axios';

function App() {
  const [role, setRole] = useState(null);
  const [students, setStudents] = useState([]);
  const [qaybta, setQaybta] = useState("Dhamaan");
  const [currentUser, setCurrentUser] = useState(null);

  useEffect(() => {
    if (role === 'admin') axios.get('http://localhost:3000/admin/students').then(res => setStudents(res.data));
  }, [role]);

  // Xisaabinta Total iyo Average
  const calculateResult = (exam) => {
    const marks = Object.values(exam).map(Number);
    const total = marks.reduce((a, b) => a + b, 0);
    const average = total / marks.length;
    return { total, average };
  };

  // Kala saarista (1-4, 5-8, 9-12)
  const filtered = students.filter(s => {
    const fNum = parseInt(s.id.substring(1, 3));
    if (qaybta === "1/4") return fNum >= 1 && fNum <= 4;
    if (qaybta === "5/8") return fNum >= 5 && fNum <= 8;
    if (qaybta === "9/12") return fNum >= 9 && fNum <= 12;
    return true;
  });

  const AdminView = () => (
    <div style={{ padding: '20px' }}>
      <h2>📊 Maamulka Imtixaannada</h2>
      <div style={{ marginBottom: '20px' }}>
        <strong>Dooro Qaybta: </strong>
        <select onChange={e => setQaybta(e.target.value)} style={{padding: '10px', borderRadius: '5px'}}>
          <option value="Dhamaan">Dhamaan 1-12</option>
          <option value="1/4">1/4 (Primary)</option>
          <option value="5/8">5/8 (Intermediate)</option>
          <option value="9/12">9/12 (Secondary)</option>
        </select>
      </div>
      <table border="1" width="100%" style={{ borderCollapse: 'collapse', textAlign: 'center' }}>
        <thead style={{background: '#2c3e50', color: 'white'}}>
          <tr>
            <th>ID</th><th>Magaca</th><th>Fasalka</th>
            <th>Xisaab</th><th>Af-Somali</th><th>Ingiriis</th><th>Total</th>
          </tr>
        </thead>
        <tbody>
          {filtered.map(s => {
            const { total } = calculateResult(s.exam);
            return (
              <tr key={s.id}>
                <td>{s.id}</td><td>{s.magaca}</td><td>{s.fasalka}</td>
                <td><input type="number" style={{width: '50px'}} onBlur={e => axios.put(`http://localhost:3000/admin/update-exam/${s.id}`, {Xisaab: e.target.value})} defaultValue={s.exam.Xisaab} /></td>
                <td><input type="number" style={{width: '50px'}} onBlur={e => axios.put(`http://localhost:3000/admin/update-exam/${s.id}`, {AfSomali: e.target.value})} defaultValue={s.exam.AfSomali} /></td>
                <td><input type="number" style={{width: '50px'}} onBlur={e => axios.put(`http://localhost:3000/admin/update-exam/${s.id}`, {Ingiriis: e.target.value})} defaultValue={s.exam.Ingiriis} /></td>
                <td style={{fontWeight: 'bold'}}>{total}</td>
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );

  return (
    <div style={{ fontFamily: 'Arial', background: '#f4f7f6', minHeight: '100vh' }}>
      {!role ? (
        <div style={{textAlign: 'center', paddingTop: '100px'}}>
          <h1>Dugsi Management System</h1>
          <button onClick={() => {
            const p = prompt("Geli Admin Password:");
            axios.post('http://localhost:3000/login', {type: 'admin', password: p}).then(() => setRole('admin')).catch(() => alert("Khalad!"));
          }} style={btnStyle}>Geli Maamule</button>
          <button onClick={() => {
            const f = prompt("Fasalka (Tusaale: Fasalka 1):");
            const id = prompt("ID-gaaga:");
            const p = prompt("Password-ka:");
            axios.post('http://localhost:3000/login', {type: 'student', id, password: p, fasalka: f})
              .then(res => { setCurrentUser(res.data); setRole('student'); }).catch(() => alert("Lama helin!"));
          }} style={btnStyle}>Geli Arday</button>
        </div>
      ) : role === 'admin' ? <AdminView /> : (
        <div style={{padding: '50px', textAlign: 'center'}}>
          <h2>Natiijada Imtixaanka: {currentUser.magaca}</h2>
          <div style={{background: 'white', padding: '30px', display: 'inline-block', borderRadius: '15px', boxShadow: '0 4px 8px rgba(0,0,0,0.1)'}}>
            {Object.entries(currentUser.exam).map(([m, d]) => <p key={m}>{m}: <strong>{d}</strong></p>)}
            <hr/>
            <h3>Total: {calculateResult(currentUser.exam).total}</h3>
            <h3>Average: {calculateResult(currentUser.exam).average}%</h3>
          </div>
        </div>
      )}
    </div>
  );
}

const btnStyle = { padding: '15px 30px', margin: '10px', fontSize: '18px', cursor: 'pointer', background: '#1a73e8', color: 'white', border: 'none', borderRadius: '10px' };
export default App;
